#include <bits/stdc++.h>
using namespace std;

vector<int> par, sz;
int find(int x){ return par[x]==x?x:par[x]=find(par[x]); }

int getId(unordered_map<string,int>& mp, const string& s){
    auto it=mp.find(s);
    if(it!=mp.end()) return it->second;
    int id=par.size();
    mp[s]=id; par.push_back(id); sz.push_back(1);
    return id;
}

int main() {
    ios_base::sync_with_stdio(false); cin.tie(NULL);
    int T; cin >> T;
    string out;
    while(T--){
        int F; cin >> F;
        unordered_map<string,int> mp;
        par.clear(); sz.clear();
        for(int i=0;i<F;i++){
            string x,y; cin >> x >> y;
            int a=getId(mp,x), b=getId(mp,y);
            int ra=find(a), rb=find(b);
            if(ra!=rb){ par[ra]=rb; sz[rb]+=sz[ra]; }
            out += to_string(sz[find(a)]);
            out += '\n';
        }
    }
    cout << out;
    return 0;
}
